import socket
import json

class GameServer:
    def __init__(self):
        self.clients = []
        self.players = {}
        self.game_state = {}

    def handle_client(self, client_socket):
        client_id = len(self.clients)
        self.clients.append(client_socket)
        print("New client connected:", client_id)

        while True:
            try:
                data = json.loads(client_socket.recv(1024).decode())
                if data["type"] == "player_position":
                    self.players[data["player_id"]] = data["position"]
                    self.broadcast_game_state()
                elif data["type"] == "client_disconnect":
                    del self.clients[client_id]
                    print("Client disconnected:", client_id)
                    break
            except json.JSONDecodeError:
                print("Invalid JSON received from client")
                break

    def broadcast_game_state(self):
        for client in self.clients:
            client.sendall(json.dumps(self.game_state).encode())

    def run(self):
        while True:
            for client in self.clients:
                try:
                    data = json.loads(client.recv(1024).decode())
                    if data["type"] == "player_position":
                        self.players[data["player_id"]] = data["position"]
                        self.broadcast_game_state()
                except json.JSONDecodeError:
                    print("Invalid JSON received from client")
            for player in self.players:
                if player not in self.game_state:
                    self.game_state[player] = {"position": self.players[player]}
            for client in self.clients:
                client.sendall(json.dumps(self.game_state).encode())